//CALCULA TEMPOS INDIVIDUAIS DOS FUNCIONARIOS //CALCULA TEMPO TOTAL DOS PRODUTOS
&ColGrupCod = RetornaCollGrupoProduto.Udp(&EmpCod,&parmGrupHie)
For Each Order EmpCod, ProCod, ProEtpFunCod, ProEtpCod Where EmpCod = &EmpCod Where ProPadForCod = &ProPadForCod when &ProPadForCod <> 0 Where GrupCod in &ColGrupCod when not &parmGrupHie.IsEmpty() Delete EndFor
Commit
&AuxPesCod = 0 For Each Order EmpCod, AptFunCod, AptDtaLct, AptHorIni, AptProCod, AptEtpCod Where EmpCod = &EmpCod //Where AptFunCod = &PesCod when not &PesCod.IsEmpty() Where (AptDtaLct >= &AptDtaLctIni or &AptDtaLctIni.IsEmpty()) and (AptDtaLct <= &AptDtaLctFin or &AptDtaLctFin.IsEmpty()) Where AptProPadForCod = &ProPadForCod when &ProPadForCod <> 0 Where AptProGrupCod in &ColGrupCod when not &parmGrupHie.IsEmpty()
&AptQtd = AptQtd &AptQtdVar = trim(toformattedString(&AptQtd)) &AptTotHor = '' &Segundosfinais = 0 RetornaOpcaoEtapaGrupo.Call(EmpCod, AptProCod, AptEtpCod, &CtrOpc)
&QtdEtapas = RetornaQtdEtapasDataHora.udp(EmpCod, AptFunCod, AptDtaLct, AptHorIni, AptHorFin)
if &AptHorIni <> AptHorIni or &AptHorFin <> AptHorFin or &AptDtaLct <> AptDtaLct RetornaDiferencaEntreHoras.Call(AptHorIni, AptHorFin, &AptTotHor, &Segundosfinais)
if &QtdEtapas > 1 and &Segundosfinais > 0 &Segundosfinais = &Segundosfinais/&QtdEtapas Endif
&SegundosTotais += &Segundosfinais
Do Case CAse &CtrOpc = 'A' //PRODUCAO &SegundosProd += &Segundosfinais
CAse &CtrOpc = 'B' //MANUTENCAO &AptQtdVar = '***' &SegundosManut += &Segundosfinais
CAse &CtrOpc = 'C' //AUSENCIA &AptQtdVar = '***'
&SegundosAusent += &Segundosfinais EndCase Endif
if &AuxPesCod <> AptFunCod if not &AuxPesCod.IsEmpty()
if (&OldAptDtaLct <> AptDtaLct) and (&AptDtaLctIni <> &AptDtaLctFin) &QtdPecasDia = 0 &Count = 0 &OldAptDtaLct = AptDtaLct &SegundosDia = 0 &SegundosDiaManut = 0 &SegundosDiaProd = 0 &SegundosDiaAusen = 0 EndIF
// RetornaDiaHoraSegundos.Call(&SegundosTotais, &TotalHora) // RetornaDiaHoraSegundos.Call(&SegundosProd, &TotalProd) // RetornaDiaHoraSegundos.Call(&SegundosManut, &TotalManu) // RetornaDiaHoraSegundos.Call(&SegundosAusent, &TotalAuse)
// print Total &QtdPecas = 0 &SegundosTotais = 0 &SegundosAusent = 0 &SegundosManut = 0 &SegundosProd = 0 eject EndIf
// print Funcionario &OldAptDtaLct.SetEmpty() EndIf
if (&OldAptDtaLct <> AptDtaLct) and (&AptDtaLctIni <> &AptDtaLctFin)
&DiaVarchar = 'DIA: ' + trim(ToformattedString(AptDtaLct)) // print imprimedia
&QtdPecasDia = 0 &Count = 0 &OldAptDtaLct = AptDtaLct &SegundosDia = 0 &SegundosDiaManut = 0 &SegundosDiaProd = 0 &SegundosDiaAusen = 0 EndIF
// RetornaNomeEtapaGrupo.Call(EmpCod, AptProCod, AptEtpCod, &CTrNom) // &Etapa = trim(str(AptEtpCod)) + ' - ' + trim(&CTrNom)
&Count += 1
Do Case CAse &CtrOpc = 'A' //PRODUCAO &QtdPecas += AptQtd &QtdPecasDia += AptQtd &SegundosDiaProd += &Segundosfinais
CAse &CtrOpc = 'B' //MANUTENCAO &SegundosDiaManut += &Segundosfinais
CAse &CtrOpc = 'C' //AUSENCIA &SegundosDiaAusen += &Segundosfinais
EndCase
//Total Diario &QtdPecasDiaVarchar = trim(toformattedString(&QtdPecasDia)) &SegundosDia += &Segundosfinais
RetornaDiaHoraSegundos.Call(&SegundosDia, &TotalHoraDia) RetornaDiaHoraSegundos.Call(&SegundosDiaManut, &TotalManutDia) RetornaDiaHoraSegundos.Call(&SegundosDiaProd, &TotalProdDia) RetornaDiaHoraSegundos.Call(&SegundosDiaAusen, &TotalAuseDia)
&AptDtaLct = AptDtaLct &AptHorIni = AptHorIni &AptHorFin = AptHorFin
// print lancamento prcGravaEtapaTotalProduto.Call(EmpCod, AptProCod, AptFunCod, AptEtpCod, &SegundosDia, &QtdPecasDia, &AptDtaLctIni, &AptDtaLctFin, &wwpContextUserName) prcGravaEtapaTotalProduto.Call(EmpCod, AptProCod, -1, AptEtpCod, &SegundosDia, &QtdPecasDia, &AptDtaLctIni, &AptDtaLctFin, &wwpContextUserName)
&AuxPesCod = AptFunCod EndFor
